#!/usr/bin/perl -wT

use strict;
use CGI qw(param);
use File::Basename;

my $cgi = new CGI;
my $log_dir = "/path/to/logs";
my $filename = param('logfile');

if (defined $filename && $filename ne '') {
    my $full_path = "$log_dir/$filename";
    
    if (-e $full_path) {
        open(my $fh, '<', $full_path) or die "Could not open file '$full_path' $!";
        
        print "Content-type: text/plain\n\n";
        
        while (my $line = <$fh>) {
            print $line;
        }
        
        close($fh);
    } else {
        print "Content-type: text/html\n\n";
        print "<h1>File not found</h1>";
    }
} else {
    print "Content-type: text/html\n\n";
    print "<h1>No logfile specified</h1>";
}